        }
    }

    void clear() {
        end = 0;
        strideHighToLow = 0;
        strideLowToHigh = 0;
        next = 0;
    }

    template<typename T>
    int writeLowInto(T *output, const T &primary) {
        return saveAndUpdate(output, primary, strideLowToHigh);
    }

    template<typename T>
    int writeHighInto(T *output, const T &other) {
        return saveAndUpdate(output, other, strideHighToLow);
    }
};

template <int WIN_SIZE_X, int WIN_SIZE_Y>
class FDWT53 {
private:
    template <bool CHECKED_LOADER>
    struct FDWT53Column {
        VerticalDWTPixelLoader<CHECKED_LOADER> loader;
        int offset;
        int pixel0, pixel1, pixel2;

        void clear() {
            offset = pixel0 = pixel1 = pixel2 = 0;
            loader.clear();
        }
    };

    typedef TransformBuffer<int, WIN_SIZE_X, WIN_SIZE_Y + 3, 2> FDWT53Buffer;
    FDWT53Buffer buffer;
    enum { STRIDE = FDWT53Buffer::VERTICAL_STRIDE };

    template <bool CHECKED>
    void initColumn(FDWT53Column<CHECKED> &column, const int *input, int sizeX, int sizeY, int colIndex, int firstY) {
        column.offset = buffer.getColumnOffset(colIndex);
        int firstX = blockIdx.x * WIN_SIZE_X + colIndex;

        if(blockIdx.y == 0) {
            column.loader.init(sizeX, sizeY, firstX, firstY);
            column.pixel2 = column.loader.loadFrom(input);
            column.pixel1 = column.loader.loadFrom(input);
            column.pixel0 = column.loader.loadFrom(input);
            column.loader.init(sizeX, sizeY, firstX, firstY + 1);
        } else {
            column.loader.init(sizeX, sizeY, firstX, firstY - 2);
            column.pixel0 = column.loader.loadFrom(input);
            column.pixel1 = column.loader.loadFrom(input);
            column.pixel2 = column.loader.loadFrom(input);
        }
    }

    template <bool CHECKED>
    void loadAndVerticallyTransform(FDWT53Column<CHECKED> &column, const int *input) {
        buffer[column.offset + 0 * STRIDE] = column.pixel0;
        buffer[column.offset + 1 * STRIDE] = column.pixel1;
        buffer[column.offset + 2 * STRIDE] = column.pixel2;

        for(int i = 3; i < (3 + WIN_SIZE_Y); i++) {
            buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
        }

        column.pixel0 = buffer[column.offset + (WIN_SIZE_Y + 0) * STRIDE];
        column.pixel1 = buffer[column.offset + (WIN_SIZE_Y + 1) * STRIDE];
        column.pixel2 = buffer[column.offset + (WIN_SIZE_Y + 2) * STRIDE];

        buffer.forEachVerticalOdd(column.offset, Forward53Predict_op);
        buffer.forEachVerticalEven(column.offset, Forward53Update_op);
    }

    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const int *in, int *out, int sizeX, int sizeY, int winSteps) {
        FDWT53Column<CHECK_LOADS> column;
        FDWT53Column<CHECK_LOADS> boundaryColumn;
        int firstY = blockIdx.y * WIN_SIZE_Y * winSteps;
        initColumn(column, in, sizeX, sizeY, threadIdx.x, firstY);

        boundaryColumn.clear();
        if(threadIdx.x < 3) {
            int colId = threadIdx.x + ((threadIdx.x == 0) ? WIN_SIZE_X : -3);
            initColumn(boundaryColumn, in, sizeX, sizeY, colId, firstY);
        }

        int outColumnIndex = parityIdx<WIN_SIZE_X>();
        int outColumnOffset = buffer.getColumnOffset(outColumnIndex);
        int outputFirstX = blockIdx.x * WIN_SIZE_X + outColumnIndex;
        VerticalDWTPixelWriter<CHECK_WRITES> writer;
        writer.init(sizeX, sizeY, outputFirstX, firstY);

        for(int w = 0; w < winSteps; w++) {
            loadAndVerticallyTransform(column, in);
            if(threadIdx.x < 3) {
                loadAndVerticallyTransform(boundaryColumn, in);
            }
            __syncthreads();

            buffer.forEachHorizontalOdd(2, WIN_SIZE_Y, Forward53Predict_op);
            __syncthreads();
            buffer.forEachHorizontalEven(2, WIN_SIZE_Y, Forward53Update_op);
            __syncthreads();

            for(int r = 2; r < (2 + WIN_SIZE_Y); r += 2) {
                writer.writeLowInto(out, buffer[outColumnOffset + r * STRIDE]);
                writer.writeHighInto(out, buffer[outColumnOffset + (r+1) * STRIDE]);
            }
            __syncthreads();
        }
    }

public:
    static void run(const int *in, int *out, int sx, int sy, int steps) {
        __shared__ FDWT53<WIN_SIZE_X, WIN_SIZE_Y> fdwt53;
        int maxX = (blockIdx.x + 1) * WIN_SIZE_X + 1;
        int maxY = (blockIdx.y + 1) * WIN_SIZE_Y * steps + 1;
        bool atRightBoundary = maxX >= sx;
        bool atBottomBoundary = maxY >= sy;

        if(atBottomBoundary) {
            fdwt53.transform<true, true>(in, out, sx, sy, steps);
        } else if(atRightBoundary) {
            fdwt53.transform<false, true>(in, out, sx, sy, steps);
        } else {
            fdwt53.transform<false, false>(in, out, sx, sy, steps);
        }
    }
};

