            AddScaledSum s3 = {f97Predict2};
            buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum_op);
            AddScaledSum s4 = {f97Update2};
            buffer.forEachVerticalEven(outColumnOffset, AddScaledSum_op);

            for(int i = 4; i < (4 + WIN_SIZE_Y); i += 2) {
                writer.writeLowInto(out, buffer[outColumnOffset + i * STRIDE] * scale97Div);
                writer.writeHighInto(out, buffer[outColumnOffset + (i + 1) * STRIDE] * scale97Mul);
            }

            for(int i = 0; i < 7; i++) {
                buffer[outColumnOffset + i * STRIDE] = last7Lines[i];
            }
            __syncthreads();
        }
    }

public:
    static void run(const float *input, float *output, int sx, int sy, int steps) {
        __shared__ FDWT97<WIN_SIZE_X, WIN_SIZE_Y> fdwt97;
        int maxX = (blockIdx.x + 1) * WIN_SIZE_X + 3;
        int maxY = (blockIdx.y + 1) * WIN_SIZE_Y * steps + 3;
        bool atRightBoundary = maxX >= sx;
        bool atBottomBoundary = sy <= maxY;

        if(atBottomBoundary) {
            fdwt97.transform<true, true>(input, output, sx, sy, steps);
        } else if(atRightBoundary) {
            fdwt97.transform<false, true>(input, output, sx, sy, steps);
        } else {
            fdwt97.transform<false, false>(input, output, sx, sy, steps);
        }
    }
};

